
theta1 = deg2rad(0); %[control:slider:090c]{"position":[18,19]}
theta2 = deg2rad(50); %[control:slider:0e33]{"position":[18,20]}
theta3 = deg2rad(-100); %[control:slider:062c]{"position":[18,22]}
theta4 = deg2rad(0); %[control:slider:97cf]{"position":[18,19]}
%                                       a, alpha, d, theta
a1 = dh_link_to_transformation_matrix(0, pi/2, 0, theta1);
a2 = dh_link_to_transformation_matrix(0.15, 0, 0, theta2);
a3 = dh_link_to_transformation_matrix(0.15, 0, 0, theta3);
ap = dh_link_to_transformation_matrix(0, pi/2, 0, -theta2 - theta3); % passive link to keep the end effector parallel to the ground
a4 = dh_link_to_transformation_matrix(0, 0, 0, theta4); % d4 might be something to get to the end of the tool frame
T02 = a1 * a2 %[output:3e5af83c]
T04 = a1 * a2 * a3 * ap * a4 % shows end effecto r position %[output:9a308db1]

%[text] 3D Plot
plot3(0,0,0, "bo", MarkerFaceColor="b") %[output:58947ec2]
hold on %[output:58947ec2]
plot3(T02(1,4), T02(2,4), T02(3,4), "go", MarkerFaceColor="g") %[output:58947ec2]
plot3(T04(1,4), T04(2,4), T04(3,4), "ro", MarkerFaceColor="r") %[output:58947ec2]
legend("Origin", "J2", "End effector") %[output:58947ec2]
grid on %[output:58947ec2]
grid minor %[output:58947ec2]
hold off %[output:58947ec2]
xlim([-0.3 0.3]) %[output:58947ec2]
ylim([-0.3 0.3]) %[output:58947ec2]
zlim([-0.3 0.3]) %[output:58947ec2]
xlabel("X") %[output:58947ec2]
ylabel("Y") %[output:58947ec2]
zlabel("Z") %[output:58947ec2]
%[text] 

